INSERT INTO `alcohols` VALUES (1,'라이터스 티얼즈 레드 헤드','Writers\' Tears Red Head','46','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',12,47,NULL,'Oloroso Sherry Butts','https://d1e2y5wc27crnp.cloudfront.net/media/core/product/thumbnail/bf2e0730-d408-454b-9121-2cfaabe38bd9.webp','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,'700ml',NULL),(2,'라이터스 티얼즈 더블 오크','Writers\' Tears Double Oak','46','WHISKY','블렌디드','Blend','BLEND',12,47,NULL,'American & French Oak','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/436faec1-79a6-47b1-a917-f9292bd6818d.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-20 09:35:24','SYSTEM','라이터즈 티얼즈 더블 오크는 두 가지의 나무향, 그리고 두 가지 스타일의 프리미엄 아이리시 위스키가 함께 어우러져 만들어낸 아주 특별한 아이리시 위스키입니다. 아일랜드 위스키의 황금기 시절의 위스키 공법을 재현한 싱글 팟 스틸 위스키와 싱글 몰트 아이리시 위스키를 미국 캔터키의 오크 버번 오크통과 프랑스의 꼬냑 지방의 오크 코냑 오크통에서 숙성시켰습니다. 세 번 증류되고, 논칠 필터(Non Chill Filtered) 공법으로 마감되어 도수 46%로 병입 된 아이리시 위스키죠. 아일랜드의 월시 가문과 프랑스 꼬냑의 리카 레트 패밀리와의 합작 위스키의 성공적인 콜라보레이션을 통해 시장성 있게 만든 제품, 바로 라이터즈 티얼즈 더블 오크입니다.','700ml',NULL),(3,'라이터스 티얼즈 코퍼 팟','Writers\' Tears Copper Pot','40','WHISKY','블렌디드 몰트','Blended Malt','BLENDED_MALT',12,47,NULL,'Bourbon Barrels','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/3efde189-0afb-467b-8213-fa5ac1f276cb.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(4,'VAT 69 블렌디드 스카치 위스키','VAT 69 Blended Scotch Whisky','40','WHISKY','블렌디드','Blend','BLEND',19,150,NULL,NULL,'https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/e7908231-a53a-4173-8672-1606252cb962.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(5,'툴리바딘 소버린','Tullibardine Sovereign','43','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',20,137,NULL,'1st fill bourbon barrel','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/dbdb9c75-6a0e-44a7-a334-17079a8c2f52.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(6,'탈라모어 듀 XO','Tullamore Dew XO','43','WHISKY','블렌디드','Blend','BLEND',12,127,NULL,'Caribbean Rum Cask Finish','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/4f8011aa-0e6a-4d78-a925-aedc76c8d355.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(7,'탈라모어 듀 더 레전더리 아이리시 위스키','Tullamore Dew The Legendary Irish Whiskey','40','WHISKY','블렌디드','Blend','BLEND',12,47,NULL,NULL,'https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/80f6f528-4681-495f-b396-1b5c433999b2.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(8,'탈라모어 듀 사이다 캐스크 피니시','Tullamore Dew Cider Cask Finish','40','WHISKY','블렌디드','Blend','BLEND',12,47,NULL,'Cider Cask Finish','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/8780cb81-8b02-421e-8d5d-81dcaa0a4062.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(9,'탈라모어 듀 14년','Tullamore Dew 14y','41.3','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',12,47,'14','Bourbon, Oloroso Sherry, Port, Madeira Finish','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/a89bcd14-b438-4d32-a20a-091de5ef750a.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(10,'탈라모어 듀 12년','Tullamore Dew 12y','40','WHISKY','블렌디드','Blend','BLEND',12,47,'12','Ex-Bourbon & Oloroso Sherry Casks','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/b655259e-0f46-48d2-8c00-94a0ae95c466.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(11,'토모어 16년','Tormore 16y','48','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,134,'16','American Oak Cask','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/739036f3-9cfe-45c7-a365-55b4fa21e0ca.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(12,'토모어 14년','Tormore 14y','43','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,134,'14','American Oak','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/10571916-ff01-4d13-b4de-0b793e95e669.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(13,'토민타울 피티탱','Tomintoul With A Peaty Tang','40','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,135,NULL,NULL,'https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/490ffe58-1d10-462a-8b07-9d1904b270c1.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(14,'토민타울 시가몰트','Tomintoul Cigar Malt','43','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,135,NULL,'Oloroso','https://d1e2y5wc27crnp.cloudfront.net/media/core/product/thumbnail/e945fed6-d01a-477f-ae28-a80515bbd7eb.webp','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM','토민타울 시가 몰트\'는 복합적이고 풍부하며 견고함을 갖춘 위스키입니다. 풍부하고 향긋한 셰리, 달콤한 몰트, 부드러운 스모크 향미가 어우러져 뛰어난 균형감을 자랑합니다. \n\n \n\n토민타울 시가 몰트는 시가 없이 위스키만으로도 완벽하지만, 좋은 품질의 시가와 함께할 때 더욱 완벽한 페어링 경험을 선사합니다. 시가 페어링을 먼저 진행할 경우, 토민타울 시가 몰트가 은은하게 품고 있는 훈연 향을 느끼기 어려울 수 있기 때문에 먼저 위스키 단독 시음을 진행한 후에 부드러운 훈연 향과 그 여운을 즐기며 본격적인 시가 페어링을 이어갈 것을 추천합니다.\n\n \n\n한편 2023년 4월, 토민타울 시가 몰트 론칭을 기념해 국내에 방문한 앵거스 던디 디스틸러스의 마스터 블렌더 이안 포티스(Iain Forteath)는 토민타울 시가 몰트를 만드는 과정에서 위스키와 시가의 밸런스에 집중했으며, 그 과정에서 무려 40가지 내외의 시가를 경험했다고 전했습니다. 또한 토민타울 시가몰트에 어울리는 시가로는 다비도프 윈스턴 처칠 더 레이트 아워, 몬테 크리스토 No.2, 파르타가스 D4를 손꼽았습니다.','700ml',NULL),(15,'토민타울 16년','Tomintoul 16y','40','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,135,'16',NULL,'https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/acdc57f9-0a5f-4653-bc90-37ff49690b0a.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(16,'토민타울 14년','Tomintoul 14y','46','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,135,'14','American oak ex-bourbon','https://d1e2y5wc27crnp.cloudfront.net/media/core/product/thumbnail/98412bf9-d373-43aa-a28c-0bfbbb7791be.webp','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,'700ml',NULL),(17,'토민타울 10년','Tomintoul 10y','40','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,135,'10','American oak ex-bourbon barrel','https://d1e2y5wc27crnp.cloudfront.net/media/core/product/thumbnail/dc2c413c-ff38-46c9-9272-4f995f587bf2.webp','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,'700ml',NULL),(18,'토버모리 21년','Tobermory 21y','46.3','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',18,136,'21','Spanish Oloroso','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/11da1b10-c444-4805-b1d8-2555d37b7e98.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(19,'토버모리 12년','Tobermory 12y','46.3','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',18,136,'12','1st Fill Ex-Bourbon & Virgin Oak','https://d1e2y5wc27crnp.cloudfront.net/media/smartorder_reservation/product/thumbnail/86f3abe8-cd34-4866-ad88-2906776b2e4d.webp','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM','토버모리 12년은 토버모리 증류소의 엔트리급 위스키로, 달콤한 과일과 향신료, 버터스카치, 약간의 짭짤한 맛이 느껴지는 위스키입니다. 아주 옅은 피트의 풍미도 함께 느껴져서 피트 위스키에 입문하고 계시는 분께도 추천드리는 싱글몰트 위스키입니다.','700ml',NULL),(20,'싱글톤 더프타운 18년','The Singleton of Dufftown 18y','40','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,31,'18','Bourbon and Sherry','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/8e36bcc7-8ddc-46a7-834d-785102b9fd67.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(21,'싱글톤 더프타운 15년','The Singleton of Dufftown 15y','40','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,31,'15','Refill ex-Bourbon Casks & PX Oloroso seasoned','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/a5f10e81-32f4-466f-b314-b48a1957ee16.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(22,'싱글톤 더프타운 12년','The Singleton of Dufftown 12y','40','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,31,'12','Seasoned PX/Oloroso and refill ex-bourbon','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/7ae9c46a-0221-44bf-92d2-0d2b03d5cb8a.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(23,'더 페이머스 그라우스 셰리 캐스크 피니시','The Famous Grouse Sherry Cask Finish','40','WHISKY','블렌디드','Blend','BLEND',19,150,NULL,'Sherry Cask Finish','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/ada5b103-466a-4682-97fe-0a1402c07443.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-20 09:35:24','SYSTEM','시작은 \'The grouse(더 그라우스)\'였습니다. 1897년, 이 위스키가 세상에 나올 당시, 상류계급 사이에는 뇌조(grouse) 사냥이 크게 유행하고 있었습니다. 창업자 메슈 글로우그(Matthew Gloag)는 이 상류계급을 겨냥하기 위해 라벨에 뇌조를 그려넣고, 위스키의 이름을 \'The grouse\'로 지었는데요. 그 작전은 실로 완벽했습니다. 사냥을 하던 상류계급에서부터 시작해 그 맛이 입소문을 타며 점차 유명세를 얻기 시작했던거죠. 마침내, 사람들 사이에서 \'그 유명한 뇌조 위스키\'로 불리게 되었고 지금의 \'The Famous Grouse(더 페이머스 그라우스)\'가 되었습니다.','700ml',NULL),(24,'더 페이머스 그라우스','The Famous Grouse Blended Scotch Whisky','40','WHISKY','블렌디드','Blend','BLEND',19,150,NULL,NULL,'https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/226a3b84-7268-4680-9146-b7ccb8b3dd04.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-20 09:35:24','SYSTEM','더 페이머스 그라우스\'의 시작은 \'더 그라우스(The grouse)\'였습니다. 1897년, 이 위스키가 세상에 나올 당시에 상류계급 사이에는 뇌조(grouse) 사냥이 크게 유행하고 있었습니다. 창업자 메슈 글로우그(Matthew Gloag)는 이 상류 계급을 겨냥하기 위해 위스키 라벨에 뇌조를 그려넣고, 위스키의 이름을 \'The grouse\'로 지은 후 출시했죠. 그 작전은 실로 완벽했습니다. 사냥을 하던 상류계급에서부터 시작해 그 맛이 입소문을 타며 점차 인지도를 얻기 시작했습니다. 마침내, 사람들 사이에서 더 그라우스는 \'그 유명한 뇌조 위스키\'로 불리게 되었고, 지금의 더 페이머스 그라우스가 탄생하게 되었습니다.     더 페이머스 그라우스가 유명해진 데에는 이유가 있습니다. 바로 최고급 몰트 위스키와 그레인 위스키를 블렌딩해 만들었기 때문입니다. 합리적인 가격임에도 높은 퀄리티에 위스키 출시 직후 놀라는 사람들이 많았죠. 현재 4대째 가족 운영 중인 더 페이머스 그라우스는 이러한 인기에 자만하지 않고 계속해서 더 나은 품질을 위해 모든 노력을 쏟고 있습니다. 그리고 스코틀랜드 내 블렌디드 위스키 판매량 1위를 기록하며 노력을 인정 받았습니다.','700ml',NULL),(25,'테렌펠리 사부','Teerenpeli Savu','43','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',2,132,NULL,'Bourbon, Pedro Ximénez','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/f99f4a06-c399-47fd-88f3-323881b3dd06.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(26,'테렌펠리 포르티','Teerenpeli Portti','43','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',2,132,NULL,'Bourbon + Port Casks Finish','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/0dd05efb-f845-47ee-b988-cfaf98316537.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(27,'테렌펠리 카스키','Teerenpeli Kaski','43','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',2,132,NULL,'Sherry','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/b23dc52b-55f3-464f-97d1-1afc080094a9.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(28,'테렌펠리 카르히','Teerenpeli Karhi','43','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',2,132,NULL,'Madeira Finished','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/4977c734-04a2-4f47-af38-b22b5338ccf4.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(29,'틸링 싱글 팟 스틸','Teeling Single Pot Still','46','WHISKY','싱글 팟 스틸','Single Pot Still','OTHER',12,139,NULL,'Virgin American Oak, Sherry, Bourbon','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/2afa19ab-c394-4004-864d-98d138a9be78.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(30,'틸링 싱글몰트','Teeling Single Malt','46','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',12,150,NULL,'Sherry/Port/Madeira/Wh. Burgundy/Cab. Sauv.','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/d7921cbf-2a9c-4eb9-be55-6a2e18b0372f.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(31,'티니닉10년','Teaninich 10y','43','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',20,138,'10',NULL,'https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/56de67c8-a692-45b2-8023-a1a54bc15b85.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(32,'탐나불린 화이트와인 캐스크','Tamnavulin White Wine Cask Edition','40','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,129,NULL,'American Oak Barrel + Sauvignon Blanc','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/17c9af0d-8295-4d93-a27d-dea45a007308.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(33,'탐나불린 셰리 캐스크','Tamnavulin Sherry Cask Edition','40','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,129,NULL,'American Oak and finish in three Sherry Casks','https://d1e2y5wc27crnp.cloudfront.net/media/smartorder_reservation/product/thumbnail/61219d8f-19b2-4320-8fdf-c3fe8dd77d3a.webp','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM','탐나불린 셰리 캐스크\'는 세 가지의 각기 다른 셰리 캐스크 숙성을 통해 풍미를 최대로 끌어 올린 싱글몰트 위스키입니다. 프루티한 맛을 극대화하기 위해 황동 증류기(Copper Pot)에서 단식 증류를 한 원액을 아메리칸 버번에서 숙성한 뒤 셰리 캐스크에서 추가 숙성을 합니다.\n\n \n\n\'탐나불린 셰리 캐스크\'를 잔에 따르면 갓 구운 타르트의 바닐라와 생강, 오렌지의 아로마가 느껴집니다. 맛에서는 천도 복숭아와 토피넛 등 달콤한 맛이 조화롭게 어우러집니다. 특히 탐나불린은  합리적인 가격 대비 뛰어난 맛으로 위스키를 입문자에게 탁월한 선택지가 될 수 있습니다.\n\n \n\n[수상 내역]\n\n \n\n2020 International Spirits Challenge Gold Medal\n\n2021 International Spirits Challenge Gold Medal\n\n2022 International Spirits Challenge Gold Medal\n\n2023 International Spirits Challenge Gold Medal','700ml',NULL),(34,'탐나불린 레드와인 캐스크','Tamnavulin Red Wine Cask Edition','40','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,129,NULL,'American Oak Barrel + Spanish Grenache','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/c8e55ea8-0303-4dab-ab7d-6698c633a9b6.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(35,'탐나불린 올로로소 쉐리 캐스크','Tamnavulin Oloroso Cask Edition','40','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,129,NULL,'American Oak & Oloroso Sherry Cask Finish','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/2504dd2d-4a94-4b12-b5b4-5cf12b703532.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(36,'탐나불린 더블 캐스크','Tamnavulin Double Cask','40','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,129,NULL,'American Oak Barrels + Sherry Cask Finish','https://d1e2y5wc27crnp.cloudfront.net/media/smartorder_reservation/product/thumbnail/e1044263-ed2b-4118-ac22-3422b4f6f998.webp','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM','가성비 좋은, 게다가 가심비까지 사로잡은 싱글몰트 위스키 ‘탐나불린 더블캐스크’를 소개합니다. ‘탐나불린 더블 캐스크’는 탐나불린 증류소의 공식 라인업 중에서도 첫번째로 출시되어, 증류소 스타일을 대표하는 위스키입니다. 이 위스키는 제품 이름대로 숙성에 두 가지 캐스크를 사용하여, 완벽한 밸런스를 갖추었습니다. 아메리칸 오크 배럴에 숙성하여 부드러운 달콤함을 더하고, 셰리 캐스크를 통해 풍부한 마무리를 선사합니다.‘탐나불린 더블 캐스크’는 많은 위스키 애호가들이 칭찬하는 앰버 골드 색깔을 띠고 있습니다. 처음 잔에 따라 ‘탐나불린 더블 캐스크’의 향을 맡으면 사과, 토피, 꿀, 부드러운 마지팬과 같은 달콤한 향기가 풍성하게 피어오릅니다. 입 안에서는 신선한 배, 복숭아, 파인애플 과실 풍미와 약간의 데메라라 설탕 맛이 맴돕니다. 그리고 스파이시하고 깔끔한 피니시로 끝을 맺습니다.','700ml',NULL),(37,'탈리스커 포트 리','Talisker Port Ruighe','45.80','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',18,128,NULL,'Port Cask Finish','https://d1e2y5wc27crnp.cloudfront.net/media/core/product/thumbnail/ddc17d4e-d0f7-4215-8e0a-43f6e2f76589.webp','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM','탈리스커 포트 리\'는 스코틀랜드 스카이 섬의 탈리스커 증류소에서 생산하는 싱글 몰트 스카치 위스키입니다. \'Port Ruighe\'는 스코틀랜드 게일어로 \'Portree\'를 의미하며, 스카이 섬의 주요 항구 도시 이름에서 유래했습니다. 이 위스키는 포트 와인 캐스크에서 마무리 숙성을 거쳐, 탈리스커 특유의 스모키함과 포트 와인의 풍부한 과일 향이 조화를 이루는 것이 특징입니다.\n\n \n\n테이스팅 노트를 살펴보면, 코에서는 바다 내음과 달콤한 풋사과와 같은 과일 향이 느껴집니다. 입안에서는 향신료와 커피의 풍미가 두드러지고, 스모키함이 점차 강해집니다. 피니시에서는 후추와 오크 노트로 이어지며, 마지막에 긴 여운이 남습니다.\n\n \n\n이 위스키는 탈리스커의 전통적인 스타일에 포트 와인 캐스크 숙성을 더해, 스모키함과 과일의 단맛이 어우러진 독특한 풍미를 선사합니다. 다양한 연령층의 위스키 애호가들에게 사랑받는 이 제품은 스트레이트나 온더록으로 즐기기에 탁월합니다.','700ml',NULL),(38,'타케츠루 퓨어 몰트','Taketsuru Pure Malt','43','WHISKY','블렌디드 몰트','Blended Malt','BLENDED_MALT',7,150,NULL,NULL,'https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/00b9f436-c188-4b66-b019-605d9cd935e9.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(39,'타케츠루 12년','Taketsuru 12y','40','WHISKY','블렌디드 몰트','Blended Malt','BLENDED_MALT',7,150,'12',NULL,'https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/5964f327-695c-40b3-8729-7252ede4829b.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(40,'설리반 코브 17년','Sullivans Cove 17y','47.6','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',1,72,'17','French Oak 2nd Fill','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/305341ca-c9ab-4bc0-926a-ae5814d167cd.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(41,'스트라스밀 12년','Strathmill 12y','43','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,79,'12',NULL,'https://d1e2y5wc27crnp.cloudfront.net/media/core/product/thumbnail/2dab7120-5e1c-4ce7-b532-8a5e839794a1.webp','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM','Flora and Fauna은 디아지오의 다양한 증류소에서 나오는 싱글몰트 위스키 컬렉션으로, 증류소가 위치한 지역의 자연 환경과 동물들을 병의 라벨에 표시하여 소량 출시됩니다.\n\n \n\n\'스트라스밀 12년\'은 버번 캐스크에서 숙성한 제품입니다. 이 싱글몰트 위스키는 달콤한 풍미와 드라이한 노트, 그리고 기분 좋은 여운을 지니고 있습니다. 익힌 과일과 향신료, 초콜릿 풍미가 풍성하게 느껴집니다. 희소한 위스키를 찾고 있다면 \'스트라스밀 12년\'은 좋은 선택지가 될 수 있습니다.','700ml',NULL),(42,'스트라티슬라 12년','Strathisla 12y','40','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,80,'12',NULL,'https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/8fc66a60-b40b-4fcb-90c8-e00a7dc44373.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(43,'스터닝 카오스','Stauning KAOS','46','WHISKY','싱글 그레인','Single Grain','OTHER',25,78,NULL,NULL,'https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/a5eb9f7f-08d4-4c56-a09a-1bf342145eac.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(44,'세인트 킬리안 피티드 리치 앤 스모키','St. Kilian Peated rich & Smoky','46','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',24,73,NULL,'70% Ex-Bourbon, 30% PX & Oloroso','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/3141f4d8-3046-41af-8dc7-427a5c9a6150.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(45,'세인트 킬리안 클래식 마일드 앤 프루티','St. Kilian Classic Mild & Fruity','46','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',24,73,NULL,'70% Ex-Bourbon, 30% PX & Oloroso','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/2e80b857-e17c-4a54-9d44-4c0aa1662a04.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(46,'스프링뱅크 30년','Springbank 30y','46','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',14,83,'30','80% Bourbon, 20% Sherry','https://d1e2y5wc27crnp.cloudfront.net/media/core/product/thumbnail/feba316f-fa83-4009-b4f0-da7467e431ed.webp','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM','스프링뱅크 30년\'은 버번 캐스크 85%, 셰리 캐스크 15%의 비율로 숙성된 싱글몰트 위스키입니다. 크리미한 질감과 짙은 열대 과일 풍미가 느껴지는 \'스프링뱅크 30년\'을 만나보세요.','700ml',NULL),(47,'스페이 크리스마스 초이스','SPEY Chairman\'s Choice','40','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',16,82,NULL,NULL,'https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/c4affed9-0ef4-4c72-9d26-df84f33b4c2e.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(48,'스뫼겐 90 프루프 배치 L003','Smögen 90 Proof L003','51.4','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',22,74,'9','Ex-bourbon barrels','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/7cbc71b5-1523-40d3-a31f-8c1b99fe0a64.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(49,'스뫼겐 90 프루프 배치 L001','Smögen 90 Proof L001','51.4','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',22,74,'9','Ex bourbon barrel','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/f3d892b6-ac2d-4b70-bbe2-2571f99a88ef.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL),(50,'스뫼겐 90 프루프 배치 L002','Smögen 90 Proof L002','51.4','WHISKY','싱글 몰트','Single Malt','SINGLE_MALT',22,74,'9','Ex-bourbon barrels','https://d3dvjqqnb91j9d.cloudfront.net/alcohols/whisky/3ed91dac-fcb5-4597-8a38-f6d54d971434.jpg','2025-05-10 09:29:30','SYSTEM','2025-08-08 06:48:16','SYSTEM',NULL,NULL,NULL);

