    (1, 'RECOMMENDED_WHISKY', '추천 큐레이션', '추천 위스키를 카드 목록으로 발행하는 큐레이션. 각 항목은 위스키 1건과 큐레이터 코멘트로 구성된다.', CAST('{"type":"object","description":"추천 큐레이션의 위스키 카드 한 항목","x-form-style":"alcohol-list","properties":{"alcoholId":{"type":"integer","format":"int64","description":"추천할 위스키의 알코올 ID","example":1,"x-field-style":"alcohol-card","x-display-name":"위스키"},"comment":{"type":"string","description":"추천 이유 또는 큐레이터 코멘트","example":"부드러운 셰리 풍미가 진하게 올라오는 입문 추천 위스키","x-field-style":"long-text","x-display-name":"큐레이터 코멘트"}},"required":["alcoholId"],"x-container":"array"}' AS JSON), CAST('{"type":"object","description":"추천 큐레이션의 위스키 카드 조회 응답","x-form-style":"alcohol-list","x-graphql":{"query":"alcohols","argFrom":"$.alcoholId","argName":"ids","argType":"[ID!]!"},"properties":{"alcoholId":{"type":"integer","format":"int64","description":"알코올 ID","example":1,"x-field-style":"plain-number","x-display-name":"위스키 ID","x-graphql":true},"comment":{"type":"string","description":"큐레이터 코멘트","example":"부드러운 셰리 풍미가 진하게 올라오는 입문 추천 위스키","x-field-style":"long-text","x-display-name":"큐레이터 코멘트"},"korName":{"type":"string","description":"알코올 한글명","example":"글렌드로낙 오리지널 12년","x-field-style":"plain-text","x-display-name":"이름","x-graphql":true},"engName":{"type":"string","description":"알코올 영문명","example":"GLENDRONACH ORIGINAL 12Y","x-field-style":"plain-text","x-display-name":"영문명","x-graphql":true},"imageUrl":{"type":"string","description":"알코올 대표 이미지 URL","example":"https://img.example.com/alcohols/1.png","x-field-style":"image-url","x-display-name":"이미지","x-graphql":true},"regionName":{"type":"string","description":"지역 또는 국가명","example":"스코틀랜드","x-field-style":"plain-text","x-display-name":"지역","x-graphql":true},"korCategory":{"type":"string","description":"한글 카테고리명","example":"싱글 몰트","x-field-style":"plain-text","x-display-name":"카테고리","x-graphql":true},"abv":{"type":"string","description":"알코올 도수","example":"43","x-field-style":"plain-text","x-display-name":"도수","x-graphql":true},"volume":{"type":"string","description":"용량","example":"700ml","x-field-style":"plain-text","x-display-name":"용량","x-graphql":true},"rating":{"type":"number","format":"double","description":"평균 별점","example":4.3,"x-field-style":"rating-display","x-display-name":"평균 별점","nullable":true,"x-graphql":true},"totalPickCount":{"type":"integer","format":"int64","description":"찜 수","example":128,"x-field-style":"count","x-display-name":"찜 수","x-graphql":true},"tags":{"type":"array","description":"테이스팅 태그 목록","example":[{"id":58,"korName":"셰리","engName":"sherry"}],"x-field-style":"tag-list","x-display-name":"테이스팅 태그","x-graphql":true,"items":{"type":"object","description":"테이스팅 태그 단건","example":{"id":58,"korName":"셰리","engName":"sherry"},"x-field-style":"tag-item","x-display-name":"태그","properties":{"id":{"type":"integer","format":"int64","description":"태그 ID","example":58,"x-field-style":"plain-number","x-display-name":"태그 ID","x-graphql":true},"korName":{"type":"string","description":"태그 한글명","example":"셰리","x-field-style":"plain-text","x-display-name":"태그명","x-graphql":true},"engName":{"type":"string","description":"태그 영문명","example":"sherry","x-field-style":"plain-text","x-display-name":"태그 영문명","x-graphql":true}},"required":["id","korName"]}}},"required":["alcoholId","korName"]}' AS JSON), 'alcohol', 1, 1),
    (2, 'WHISKY_PAIRING', '위스키 페어링', '위스키 1건과 그 위스키에 어울리는 페어링 음식 N개를 묶어 소개하는 큐레이션.', CAST('{"type":"object","description":"위스키와 페어링 음식 묶음 한 항목","x-form-style":"pairing-list","properties":{"alcoholId":{"type":"integer","format":"int64","description":"페어링 기준 위스키 ID","example":1,"x-field-style":"alcohol-card","x-display-name":"위스키"},"comment":{"type":"string","description":"위스키에 대한 설명 또는 기대평","example":"셰리 캐스크의 단맛이 디저트와 잘 어울린다.","x-field-style":"long-text","x-display-name":"위스키 기대평"},"pairings":{"type":"array","description":"해당 위스키와 함께 보여줄 페어링 음식 목록","example":[{"itemName":"부드러운 티라미수 초콜릿","itemImageUrl":"https://images.unsplash.com/photo-1551024601-bec78aea704b?w=480","pairingNote":"진한 초콜릿 향이 위스키의 단맛과 이어진다."}],"x-field-style":"pairing-food-list","x-display-name":"위스키와 페어링할 음식","minItems":1,"items":{"type":"object","description":"페어링 음식 한 항목","example":{"itemName":"부드러운 티라미수 초콜릿","itemImageUrl":"https://images.unsplash.com/photo-1551024601-bec78aea704b?w=480","pairingNote":"진한 초콜릿 향이 위스키의 단맛과 이어진다."},"x-field-style":"none","x-display-name":"페어링 음식","properties":{"itemName":{"type":"string","description":"페어링 음식명","example":"부드러운 티라미수 초콜릿","x-field-style":"plain-text","x-display-name":"음식명"},"itemImageUrl":{"type":"string","description":"페어링 음식 이미지 URL","example":"https://images.unsplash.com/photo-1551024601-bec78aea704b?w=480","x-field-style":"image-url","x-display-name":"음식 이미지"},"pairingNote":{"type":"string","description":"페어링 설명","example":"진한 초콜릿 향이 위스키의 단맛과 이어진다.","x-field-style":"long-text","x-display-name":"페어링 설명"}},"required":["itemName","pairingNote"]}}},"required":["alcoholId","pairings"],"x-container":"array"}' AS JSON), CAST('{"type":"object","description":"위스키 페어링 카드 조회 응답","x-form-style":"pairing-list","x-graphql":{"query":"alcohols","argFrom":"$.alcoholId","argName":"ids","argType":"[ID!]!"},"properties":{"alcoholId":{"type":"integer","format":"int64","description":"알코올 ID","example":1,"x-field-style":"plain-number","x-display-name":"위스키 ID","x-graphql":true},"comment":{"type":"string","description":"위스키 설명 또는 기대평","example":"셰리 캐스크의 단맛이 디저트와 잘 어울린다.","x-field-style":"long-text","x-display-name":"위스키 기대평"},"korName":{"type":"string","description":"알코올 한글명","example":"글렌드로낙 오리지널 12년","x-field-style":"plain-text","x-display-name":"이름","x-graphql":true},"engName":{"type":"string","description":"알코올 영문명","example":"GLENDRONACH ORIGINAL 12Y","x-field-style":"plain-text","x-display-name":"영문명","x-graphql":true},"imageUrl":{"type":"string","description":"알코올 대표 이미지 URL","example":"https://img.example.com/alcohols/1.png","x-field-style":"image-url","x-display-name":"이미지","x-graphql":true},"korCategory":{"type":"string","description":"한글 카테고리명","example":"싱글 몰트","x-field-style":"plain-text","x-display-name":"카테고리","x-graphql":true},"abv":{"type":"string","description":"알코올 도수","example":"43","x-field-style":"plain-text","x-display-name":"도수","x-graphql":true},"volume":{"type":"string","description":"용량","example":"700ml","x-field-style":"plain-text","x-display-name":"용량","x-graphql":true},"rating":{"type":"number","format":"double","description":"평균 별점","example":4.3,"x-field-style":"rating-display","x-display-name":"평균 별점","nullable":true,"x-graphql":true},"pairings":{"type":"array","description":"페어링 음식 목록","example":[{"itemName":"부드러운 티라미수 초콜릿","itemImageUrl":"https://images.unsplash.com/photo-1551024601-bec78aea704b?w=480","pairingNote":"진한 초콜릿 향이 위스키의 단맛과 이어진다."}],"x-field-style":"pairing-food-list","x-display-name":"페어링 음식","items":{"type":"object","description":"페어링 음식 한 항목","example":{"itemName":"부드러운 티라미수 초콜릿","itemImageUrl":"https://images.unsplash.com/photo-1551024601-bec78aea704b?w=480","pairingNote":"진한 초콜릿 향이 위스키의 단맛과 이어진다."},"x-field-style":"none","x-display-name":"페어링 음식","properties":{"itemName":{"type":"string","description":"페어링 음식명","example":"부드러운 티라미수 초콜릿","x-field-style":"plain-text","x-display-name":"음식명"},"itemImageUrl":{"type":"string","description":"페어링 음식 이미지 URL","example":"https://images.unsplash.com/photo-1551024601-bec78aea704b?w=480","x-field-style":"image-url","x-display-name":"음식 이미지"},"pairingNote":{"type":"string","description":"페어링 설명","example":"진한 초콜릿 향이 위스키의 단맛과 이어진다.","x-field-style":"long-text","x-display-name":"페어링 설명"}},"required":["itemName","pairingNote"]}}},"required":["alcoholId","korName","pairings"]}' AS JSON), 'alcohol', 1, 1),
    (3, 'WHISKY_TASTING_EVENT', '위스키 시음회', '시음회 날짜, 장소, 참가 정보와 시음 위스키 라인업을 함께 발행하는 이벤트형 큐레이션.', CAST('{"type":"object","description":"위스키 시음회 큐레이션 등록 요청","x-form-style":"tasting-form","properties":{"eventDate":{"type":"string","format":"date","description":"시음회 날짜","example":"2025-06-15","x-field-style":"none","x-display-name":"시음회 날짜"},"eventTime":{"type":"string","description":"시음회 시간","example":"19:30","x-field-style":"none","x-display-name":"시음회 시간"},"barAddress":{"type":"string","description":"장소 및 바 주소","example":"서울 강남구 테헤란로 123","x-field-style":"plain-text","x-display-name":"장소 및 바(bar) 주소"},"detailAddress":{"type":"string","description":"상세 주소","example":"2층 도시남 바","x-field-style":"plain-text","x-display-name":"상세 주소"},"isRecruiting":{"type":"boolean","description":"시음회 참여자를 모집할지 여부","example":true,"x-field-style":"none","x-display-name":"참여자 모집 여부"},"entryFee":{"type":"integer","minimum":0,"description":"참가비","example":75000,"x-field-style":"plain-number","x-display-name":"참가비(1인당)"},"capacity":{"type":"integer","minimum":1,"description":"총 모집 인원수","example":20,"x-field-style":"plain-number","x-display-name":"총 모집 인원수"},"applicationLink":{"type":"string","description":"신청 링크","example":"https://forms.example.com/tasting","x-field-style":"plain-text","x-display-name":"신청링크"},"guideText":{"type":"string","description":"시음회 안내사항","example":"시작 10분 전 입장해 주세요.","x-field-style":"long-text","x-display-name":"안내사항"},"alcohols":{"type":"array","description":"시음 위스키 라인업","example":[{"alcoholId":1,"comment":"첫 잔으로 가볍게 시작하는 위스키"}],"x-field-style":"alcohol-card-list","x-display-name":"시음 위스키","minItems":1,"items":{"type":"object","description":"시음 위스키 한 항목","example":{"alcoholId":1,"comment":"첫 잔으로 가볍게 시작하는 위스키"},"x-field-style":"none","x-display-name":"시음 위스키","properties":{"alcoholId":{"type":"integer","format":"int64","description":"알코올 ID","example":1,"x-field-style":"alcohol-card","x-display-name":"위스키"},"comment":{"type":"string","description":"시음 위스키 설명","exampl