-- ============================================================
-- verification summary
-- ============================================================

SELECT 'regions' AS tbl, COUNT(*) AS cnt FROM regions
UNION ALL SELECT 'distilleries', COUNT(*) FROM distilleries
UNION ALL SELECT 'alcohols', COUNT(*) FROM alcohols
UNION ALL SELECT 'tasting_tags', COUNT(*) FROM tasting_tags
UNION ALL SELECT 'alcohols_tasting_tags', COUNT(*) FROM alcohols_tasting_tags
UNION ALL SELECT 'curation_spec', COUNT(*) FROM curation_spec
UNION ALL SELECT 'curation', COUNT(*) FROM curation
UNION ALL SELECT 'curation_extension', COUNT(*) FROM curation_extension
UNION ALL SELECT 'users', COUNT(*) FROM users
UNION ALL SELECT 'reviews', COUNT(*) FROM reviews
UNION ALL SELECT 'ratings', COUNT(*) FROM ratings
UNION ALL SELECT 'picks', COUNT(*) FROM picks;

SELECT c.id, s.code AS spec_code, c.display_order AS ord, c.name
FROM curation c
JOIN curation_spec s ON c.spec_id = s.id
ORDER BY s.code, c.display_order, c.id;
